### 2) `src/gateway/boot.ts`

#### A. Add deterministic session resolver (no hardcoded-only routing)

**Insert after `buildBootPrompt(...)` function (after line 122), before `runBootMd(...)`:**
```ts
function resolveBootSessionId(workspacePath: string, preferredSessionId?: string): string {
  if (preferredSessionId && preferredSessionId.trim()) return preferredSessionId.trim();

  const sessionsDir = path.join(workspacePath, '.prometheus', 'sessions');
  if (!fs.existsSync(sessionsDir)) return 'boot-startup';

  const files = fs.readdirSync(sessionsDir).filter(f => f.endsWith('.json'));
  let bestSessionId = '';
  let bestTs = 0;

  for (const file of files) {
    try {
      const full = path.join(sessionsDir, file);
      const raw = fs.readFileSync(full, 'utf-8');
      const parsed = JSON.parse(raw) as any;
      const sessionId = String(parsed?.id || file.replace(/\.json$/, ''));

      if (
        !sessionId ||
        sessionId === 'boot-startup' ||
        sessionId.startsWith('task_') ||
        sessionId.startsWith('cron_') ||
        sessionId.startsWith('team_dispatch_')
      ) {
        continue;
      }

      const updatedAt = Number(parsed?.updatedAt || parsed?.lastUpdated || parsed?.timestamp || 0);
      const fileMtime = fs.statSync(full).mtimeMs || 0;
      const ts = Math.max(updatedAt, fileMtime);

      if (ts > bestTs) {
        bestTs = ts;
        bestSessionId = sessionId;
      }
    } catch {
      // ignore invalid session files
    }
  }

  return bestSessionId || 'boot-startup';
}
```

